def gen(rng, size):
    alpha = 'abc'
    def make():
        n = rng.randint(1, 12)
        return ''.join(rng.choice(alpha) for _ in range(n))
    s = make()
    w = [make() for _ in range(rng.randint(1, min(size, 50)))]
    return [s, w]

