class Solution:
    def expressiveWords(self, s, words):
        def rle(t):
            res = []
            i = 0
            while i < len(t):
                j = i
                while j < len(t) and t[j] == t[i]:
                    j += 1
                res.append((t[i], j - i))
                i = j
            return res
        target = rle(s)
        count = 0
        for w in words:
            wr = rle(w)
            if len(wr) != len(target):
                continue
            ok = True
            for (tc, tn), (wc, wn) in zip(target, wr):
                if tc != wc:
                    ok = False
                    break
                if tn == wn:
                    continue
                if tn >= 3 and tn >= wn:
                    continue
                ok = False
                break
            if ok:
                count += 1
        return count

