class Solution:
    def expressiveWords(self, s, words):
        def groups(t):
            out = []
            prev = None
            cnt = 0
            for ch in t:
                if ch == prev:
                    cnt += 1
                else:
                    if prev is not None:
                        out.append((prev, cnt))
                    prev = ch
                    cnt = 1
            if prev is not None:
                out.append((prev, cnt))
            return out
        g = groups(s)
        total = 0
        for w in words:
            gw = groups(w)
            if len(gw) != len(g):
                continue
            good = True
            for (c1, n1), (c2, n2) in zip(g, gw):
                if c1 != c2 or n1 < n2 or (n1 < 3 and n1 != n2):
                    good = False
                    break
            if good:
                total += 1
        return total

