var expressiveWords = function(s, words) {
    function groups(t) {
        const out = [];
        let prev = null, cnt = 0;
        for (const ch of t) {
            if (ch === prev) cnt++;
            else {
                if (prev !== null) out.push([prev, cnt]);
                prev = ch;
                cnt = 1;
            }
        }
        if (prev !== null) out.push([prev, cnt]);
        return out;
    }
    const g = groups(s);
    let total = 0;
    for (const w of words) {
        const gw = groups(w);
        if (gw.length !== g.length) continue;
        let good = true;
        for (let i = 0; i < g.length; i++) {
            const [c1, n1] = g[i];
            const [c2, n2] = gw[i];
            if (c1 !== c2 || n1 < n2 || (n1 < 3 && n1 !== n2)) {
                good = false;
                break;
            }
        }
        if (good) total++;
    }
    return total;
};
